  ('5b3e681e-b1f2-0612-05f7-e3f1ff52828d', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Joselito (Jamones Joselito S.A.)', '', 'Guijuelo, Salamanca, Castilla y León', 'L', TRUE, 'joselito.com', 'Founded 1868, sixth generation family business. Globally the most-recognized Iberian ham brand; pioneers of "Añada" (vintage) labeling for Iberian ham. Markets ~40,000 Gran Reserva pieces/year, cured 24-30 months; iconic in Michelin-starred restaurants worldwide. Whole leg ~€70/kg retail. Premium positioning, no co-pack/private-label work.', 'L3', '["Jamón de Guijuelo DOP"]'::jsonb),
  ('dfb64971-b333-0943-9224-3167d9fd4789', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Cinco Jotas / 5J (Sánchez Romero Carvajal)', 'Osborne Group', 'Jabugo, Huelva, Andalucía', 'L', TRUE, 'cincojotas.com', 'Founded 1879 by Juan Rafael Sánchez Romero; Spain''s first 100% Iberian acorn-fed pure-pig slaughterhouse in Jabugo. Now part of Osborne Group. Cured 36+ months in Sierra de Aracena natural cellars. Recognized internationally; "Superior Taste Awards" European-best-ham winner. Whole leg ~€70/kg. Highly distributed via El Corte Inglés Gourmet Experience and premium gastronomy globally.', 'L3', '["Jamón de Jabugo DOP"]'::jsonb),
  ('4a8cfddc-4ae7-922f-a292-67838cecabb4', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Beher / Bernardo Hernández', '', 'Guijuelo, Salamanca', 'L', TRUE, 'beher.com', 'Family-owned Guijuelo producer; produces from own Salamanca farms plus Extremadura-rented dehesa for montanera. "Etiqueta de Oro" line is canonical Bellota tier. Whole leg ~€45/kg. Strong wholesale and Spain-domestic trade; expanding EU export.', 'L3', '["Jamón de Guijuelo DOP"]'::jsonb),
  ('ab552cbf-bc03-f5f6-f76b-bf1df254f98b', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Carrasco Ibéricos', '', 'Guijuelo, Salamanca', 'M', TRUE, 'carrascoibericos.com', 'Four-generation family producer in Guijuelo; pure-bred Black Iberian pigs raised in Salamanca-Extremadura dehesa. Premium positioning with intense aromatic cures. Whole leg ~€52/kg. Known among collectors and gourmets as a "true tradition" producer with consistent quality.', 'L3', '["Jamón de Guijuelo DOP"]'::jsonb),
  ('55fc7afe-0fb5-6d8a-2000-432000a86774', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Maldonado Ibéricos', '', 'Alburquerque, Badajoz, Extremadura', 'M', TRUE, 'ibericosmaldonado.com', 'Founded 1992 (Sabas + Manuel Maldonado); known for the world''s most expensive ham — exclusive "Albarragena" selection up to €1,500/piece, only 100 units/year. Pure-bred Iberian DNA-verified by University of Córdoba. Ultra-premium gift/luxury tier; very limited supply.', 'L3', '["Dehesa de Extremadura DOP"]'::jsonb),
  ('50103a66-1896-9af1-854e-bcbde6a8e2d3', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Dehesa Maladúa (Eduardo Donato)', '', 'Sierra de Aracena, Huelva (Jabugo DOP zone)', 'S', TRUE, 'dehesamaladua.com', 'Pioneer in reviving the rare "Manchado de Jabugo" Iberian sub-breed (51 producers protect the lineage). Hams cured up to 7 years; ~€500/kg, the most expensive ham in the world (~€4,100/leg). 2016 Biofach (Nuremberg) organic-food fair top prize. For Iriska: ultra-prestige tier, limited availability.', 'L3', '["Jamón de Jabugo DOP"]'::jsonb),
  ('32b207b1-66ec-274c-5f90-f83274829975', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Juan Pedro Domecq', '', 'Sierra de Huelva (Jabugo DOP zone)', 'M', TRUE, 'jamonesjuanpedrodomecq.com', 'Domecq family Iberian-pig hams cured 36+ months in Jabugo cellars. Whole leg ~€54/kg. Known for traditional artisanal process. Solid mid-premium positioning.', 'L3', '["Jamón de Jabugo DOP"]'::jsonb),
  ('97edc518-bedf-9179-3955-98c1c0749516', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'COVAP (Cooperativa del Valle de los Pedroches) — Alta Expresión', '', 'Valle de los Pedroches, Córdoba, Andalucía', 'L', TRUE, 'covap.es', 'Major Pedroches cooperative; "Alta Expresión" is the premium acorn-cured tier (36+ months). Cooperative model = volume + DOP discipline. Strong distribution into supermarket gourmet sections. Whole leg ~€45/kg. Diversified beyond ham (also dairy, meat).', 'L3', '["Jamón de Los Pedroches DOP"]'::jsonb),
  ('1ff2bf58-b5c7-f9da-b600-8a541400ec35', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Jamones Aljomar', '', 'Guijuelo, Salamanca', 'M', TRUE, 'aljomar.es', 'Founded 1989 by Alfonso Sánchez Bernal. Vertically integrated (own farms, feed, slaughterhouse, cure). Known for traceability and consistency. Solid HoReCa positioning, less retail-visible than Joselito/5J.', 'L3', '["Jamón de Guijuelo DOP"]'::jsonb),
  ('3eecd022-b311-857f-e9bc-0dca8c5890ba', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Jamones Sierra Mayor de Jabugo', '', 'Jabugo, Huelva', 'M', TRUE, '', 'Affiliated with Consorcio de Jabugo. "Gran 10 Vetas" 36+ months artisan. Whole leg ~€56/kg. Mid-premium tier; less internationally distributed than Joselito/5J.', 'L3', '["Jamón de Jabugo DOP"]'::jsonb),
  ('399a6563-63d7-b12b-06e3-8b68d236f164', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Sierra de Sevilla (Jamones)', '', 'Sierra Norte de Sevilla, Andalucía (Jabugo DOP zone-adjacent)', 'M', TRUE, '', 'Limited production (~14,000 pure-Iberian pigs/year). Aromatic, intensely flavored hams with subtle sweetness. Whole leg ~€42/kg. Boutique premium positioning.', 'L3', '["Jamón de Jabugo DOP (some lines)"]'::jsonb),
  ('2ea6d1b7-c892-c37a-b1e8-12b2692be9ed', 'ES', 'Spain', 'Iberian Ham Producers (Jamón Ibérico)', 'Jamones Eíriz / Eíriz Jabugo', '', 'Corteconcepción, Sierra de Aracena, Huelva', 'S', TRUE, 'eirizjabugo.com', 'Family-run Jabugo producer; recognized in international competitions. Mid-tier artisanal, less corporate than 5J/Joselito.', 'L3', '["Jamón de Jabugo DOP"]'::jsonb),
