  ('0b57b2a0-ca39-5870-8c76-2442d195236c', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Conservas Dardo', '', 'Rías Baixas, Galicia', 'M', NULL, 'conservasdardo.com', 'Premium cockles, mussels, clams, razor clams, scallops. Cockle 35/45 caliber is core SKU (€8-13/can). Strong artisanal positioning between volume-Frinsa and ultra-premium Paco Lafuente.', 'L3', '[]'::jsonb),
  ('6cf82ad3-d14f-b53d-678b-a05a25bf819c', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Conservas Paco Lafuente', '', 'Galicia', 'M', TRUE, '', '"Vintage" sardines pioneer (printed harvest year, like wine). Pickled mussels reference (€9-11/can, 8-12 size). Premium cockles 20/30 caliber. Reference brand among Galician canned-food collectors.', 'L3', '[]'::jsonb),
  ('f6f0fa2f-f0e4-3d24-bd75-651b9c62bc6a', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Real Conservera Española', '', 'Cambados, Galicia', 'M', TRUE, 'realconservera.com', '"World''s 101 Best Canned Products from the Sea" award (2023). Specialty: natural mussels (no additives — pure ría flavor). Premium positioning.', 'L3', '["Mejillón de Galicia DOP"]'::jsonb),
  ('4b98a891-fb26-53d8-7393-5e576778ff06', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Conservas Daporta (Albo / Hijos de Carlos Albo)', '', 'Vilanova de Arousa, Pontevedra', 'L', TRUE, 'conservasdaporta.com', 'Premium Galician canner, broad seafood range. Daporta-line cockles benchmark. Strong distribution. Note: separate from Conservas Albo (different Albo lineage).', 'L3', '["Mejillón de Galicia DOP"]'::jsonb),
  ('283a1ec3-0786-f231-fd2f-8de1a0a8b205', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Conservas Dani', '', 'Galicia', 'M', NULL, 'conservasdani.com', 'Most affordable major Galician brand; consistent quality. Spicy mussels among Spain''s best-selling tinned mussels (€3-5/can). Strong supermarket distribution. Volume-tier HoReCa option.', 'L3', '[]'::jsonb),
  ('6af94ace-07a3-aaca-6ed5-d2619cbd2b8d', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'BayMar (BayMar El Gigante)', '', 'Galicia', 'M', NULL, 'baymar.es', 'Premium cockle specialist (30/40 caliber); strong Bacalalo-and-gourmet-shop trade. Mid-premium positioning.', 'L3', '[]'::jsonb),
  ('ff5bbbd4-d7dd-9b8f-0779-da3ce9e792e2', 'ES', 'Spain', 'Conservas Gallegas (Galician Seafood — Mussels, Cockles, Razor Clams, Sardines, Octopus)', 'Los Peperetes', '', 'Carril, Pontevedra', 'M', TRUE, 'lospeperetes.com', 'Highly prestigious; David Beckham fan reportedly. Uses ONLY Mejillón de Galicia PDO-certified raw material. Premium fried-mussels-in-escabeche specialty.', 'L3', '["Mejillón de Galicia DOP"]'::jsonb),
  ('7a55856c-beaa-2e89-7681-2457d96b8e7f', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'Conservas El Navarrico', '', 'San Adrián, Navarra', 'M', TRUE, 'navarrico.com', 'Premier Navarra conservas brand; piquillo peppers flame-roasted, hand-peeled WITHOUT water (preserves flavor). Multi-format range (200g, 325g, 425g tin, 1.96kg restaurant catering tin). Reference for high-end Navarra conservas. Wide product line including white asparagus, garbanzos, alcachofas alla romana style, fabes asturianas.', 'L3', '["Pimiento del Piquillo de Lodosa DOP", "Espárrago de Navarra IGP"]'::jsonb),
  ('9b61ae35-13e4-0cc7-9d22-7f52496d7e94', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'Rosara (Conservas Artesanas Rosara)', '', 'Navarra', 'M', TRUE, 'rosara.com', 'Hand-prepared, beech-wood-fire-roasted piquillos. DOP-certified with numbered counter-label on each container. Diverse line including Tudela artichokes, Granja judiones, Asturian fabes, sin-azúcar lines. Mid-premium artisanal positioning.', 'L3', '["Pimiento del Piquillo de Lodosa DOP", "Espárrago de Navarra IGP"]'::jsonb),
  ('74a79342-747d-e70a-a7e5-fbb29601fa0b', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'Señorío de Sarría', '', 'Puente la Reina, Navarra', 'M', NULL, 'senoriodesarria.com', 'Estate-based Navarra producer; multi-product (oil, conservas, wines). Premium gift-and-gourmet positioning.', 'L3', '["Pimiento del Piquillo de Lodosa DOP / Aceite de Navarra DOP"]'::jsonb),
  ('b321a640-a171-e0d0-53e1-3914843f7d7f', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'IAN Conservas / Carretilla', '', 'Tudela, Navarra', 'L', TRUE, 'ian.es / carretilla.com', 'Major Spanish vegetable conservas group; volume positioning. Reliable for non-DOP volume sourcing; mid-tier on DOP-piquillo and asparagus categories.', 'L3', '[]'::jsonb),
  ('651553b1-003a-0a42-f56a-8022199c83a4', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'Pimientos del Piquillo de Lodosa Consejo Regulador (members)', '', '', 'M', NULL, '', '', 'L3', '[]'::jsonb),
  ('a53e0699-ebe0-0380-ebbb-5b5b9317e566', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'La Catedral de Navarra (also conservas vegetales line)', '', '', 'M', NULL, '', '', 'L3', '[]'::jsonb),
  ('2f3edb7b-5bdb-edbd-f7f2-1eaa021d5068', 'ES', 'Spain', 'Conservas Vegetales (Piquillo, Asparagus, Beans)', 'Conservas El Capricho', '', 'Navarra', 'M', NULL, '', 'Affordable premium positioning; good distribution.', 'L3', '[]'::jsonb),
  ('86e5222e-3465-91cf-6e36-97173a7544e9', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Sanchis Mira (Antiu Xixona, La Fama brands)', '', 'Jijona/Xixona, Alicante', 'L', TRUE, 'antiuxixona.com', 'Largest Spanish turrón producer; Mercadona (Hacendado private label) interproveedor. Founded 1932 (Vicente Sanchis Mira); 4 production plants in Jijona, ~40,000 m². Brands: Antiu Xixona, La Fama. Workforce 500+ in peak production. Volume-and-private-label leader.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('feeb0157-5e2b-4700-7ed8-8e18b5656611', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Confectionary Holding (El Lobo, 1880, Doña Jimena, Imperial Toledana, Clair de Lune brands)', '', 'Jijona, Alicante', 'L', TRUE, 'confectionaryholding.com', 'Owns the historic **1880** (premium tier — "the most expensive turrón in the world") and **El Lobo** (heritage). Plus Doña Jimena, Imperial Toledana. Strong premium-and-volume positioning. Museo del Turrón is at the El Lobo-1880 factory. Reference for premium Spanish Christmas-confection HoReCa.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('f967bdea-121c-51bb-adf5-a68c7fd886ea', 'ES', 'Spain', 'Turrón / Christmas Confection', 'José Garrigós (Turrón 25, La Flor de Jijona, El Castillo de Jijona, Turrones Coloma, El Antiguo brands)', '', 'Jijona, Alicante', 'M', TRUE, 'turronesjgarrigos.com', '~€17-20M revenue. Multi-brand portfolio mixing private-label co-pack and own brands. Coloma is heritage premium. Reliable mid-tier HoReCa.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('9d6e4a5d-175e-d97f-f834-2734329c6474', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Turrones Picó (La Abeja de Oro brand)', '', 'Jijona, Alicante', 'M', TRUE, 'turronpico.com', 'Heritage brand (1882 founded by Santiago Pico and María Jerez, 4 generations). ~€15-16M revenue. Distinctive TV-advertising legacy in Spain. Reliable mid-premium positioning.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('f2057b34-1f1c-f0dd-195e-558d2052110c', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Turrones Vicens', '', 'Agramunt, Lleida (Catalan tradition — distinct from Jijona)', 'L', TRUE, 'vicens.com', 'Founded 1775 (Velasco family); among Spain''s largest turrón producers. Catalan-style; chef collaborations (Albert Adrià, Paco Torreblanca, Christian Escribà, Jordi Roca, Oriol Balaguer). Premium-and-innovation positioning. **Note: not Turrón de Jijona/Alicante IGP** — Catalan separate tradition.', 'L3', '["broader Catalan turrón tradition (note: not Jijona/Alicante IGP)"]'::jsonb),
  ('c056b79a-aeef-b326-f57a-a48cadca89c3', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Coloma García Artesanos', '', 'Jijona, Alicante', 'M', NULL, 'colomagarcia.com', 'Family artisan factory founded 1961; awarded "Craft Brand Valencia" 2003 by Valencian government. Two ranges: Classic Selection (accessible) and Gourmet Selection (premium). Strong artisanal positioning.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('68c091b1-84c8-c035-78fb-81ac0623a964', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Hijos de Manuel Picó (Turrodelia, Longevity, El Enjambre brands)', '', 'Jijona', 'M', NULL, 'hijosdemanuelpico.com', 'Specialty: cream-of-turrón ("Turrodelia Gourmet"), traditional Jijona/Alicante turrón, Turrón a la Piedra. Marcona almond focus. Mid-premium artisanal.', 'L3', '["Turrón de Jijona IGP", "Turrón de Alicante IGP"]'::jsonb),
  ('0779e78b-cb63-22e4-967f-99b52d93012b', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Almendra y Miel (related to Confectionary Holding 1880/El Lobo)', '', '', 'M', NULL, '', '', 'L3', '[]'::jsonb),
  ('909c3039-3772-ecd9-3101-25ab32e70dc9', 'ES', 'Spain', 'Turrón / Christmas Confection', 'Turrones Espí, Picó, Sirvent, Coloma, etc. (mid-tier IGP-Consejo members)', '', '', 'M', NULL, '', '', 'L3', '[]'::jsonb),
  ('59dec40f-af5e-a0c9-0444-f63b170ac238', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'La Dalia (Pimentón y Especias La Dalia / José María Hernández S.L.)', '', 'Jaraíz de la Vera, Cáceres, Extremadura', 'L', TRUE, 'pimentonladalia.com', 'Founded 1913. The first commercial Pimentón de la Vera DOP producer; family-owned, granite stone-mill traditional methods. Three SKU lines: Dulce (sweet), Agridulce (bittersweet), Picante (hot). Iconic gold tin packaging. Reference brand for premium Spanish smoked paprika globally.', 'L3', '["Pimentón de la Vera DOP"]'::jsonb),
  ('e8e38b68-9b92-34b8-8efb-4614586aa4fb', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'La Chinata', '', 'Plasencia, Cáceres, Extremadura', 'L', TRUE, 'lachinata.com', 'Family-owned, third generation. Pimentón de la Vera DOP plus diversified gourmet line (paella spices, smoked oils) and EVOO-based cosmetics. Modern brand identity; strong international distribution; competing tier with La Dalia.', 'L3', '["Pimentón de la Vera DOP"]'::jsonb),
  ('4da29f44-5c9f-eb7e-cf9c-16e39755b6eb', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'Caballo de Oros (Pimentón Caballo de Oros)', '', 'Jaraíz de la Vera, Cáceres', 'M', NULL, 'caballodeoros.com', 'Founded 1938; family-run heritage. Traditional oak-wood smoking. Also produces "El Galgo" organic unsmoked paprika.', 'L3', '["Pimentón de la Vera DOP"]'::jsonb),
  ('28073472-a30a-b91a-a1c5-7fc51a7ed623', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'Hecho en La Vera', '', 'La Vera, Cáceres', 'M', NULL, '', 'Founded 1940; family-owned. Pimentón de la Vera DOP traditional production. Mid-tier premium positioning.', 'L3', '["Pimentón de la Vera DOP"]'::jsonb),
  ('ff95b509-4f0f-ca18-d60e-343f4ed5ecc7', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'Vegacáceres (Mateos family)', '', 'Cáceres', 'M', NULL, 'vegacaceres.es', 'Founded 1946; 70+ years experience. International distribution; traditional Mateos-family methods.', 'L3', '["Pimentón de la Vera DOP"]'::jsonb),
  ('7054535d-91ec-0aa2-51db-4a3cba0dd45b', 'ES', 'Spain', 'Paprika / Saffron / Spices', 'Verdú Cantó Saffron Spain', '', 'Novelda, Alicante', 'L', TRUE, 'vcsaffron.com', 'Major Spanish saffron operator; sources Azafrán de la Mancha DOP and other Spanish saffrons. Volume-and-premium tiers. Reference brand for HoReCa saffron sourcing in Spain.', 'L3', '["Azafrán de la Mancha DOP (sourcing-and-distribution)"]'::jsonb),
  ('d170edd7-fe5e-b866-7394-db3a60385a98', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Vinagres de Yema (Bodegas Páez Morilla / González Byass / Lustau)', '', 'Jerez de la Frontera, Cádiz, Andalucía', 'L', TRUE, 'gonzalezbyass.com / lustau.es / valdespino.com', 'González Byass (Tio Pepe), Lustau, Valdespino, Bodegas Tradición — the major Jerez sherry houses also produce Vinagre de Jerez DOP at Reserva and Gran Reserva tiers. Lustau in particular has strong vinegar-specific premium positioning. Solera-aged. Reference cluster for Iriska sherry-vinegar HoReCa sourcing.', 'L3', '["Vinagre de Jerez DOP"]'::jsonb),
  ('cb1da0a5-e231-79d1-c6c1-b5d182621d06', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Páez Morilla (Bodegas Páez Morilla)', '', 'Sanlúcar de Barrameda, Cádiz', 'M', NULL, 'paezmorilla.com', 'Specialist Vinagre de Jerez producer; multiple Reserva tiers. Premium positioning.', 'L3', '["Vinagre de Jerez DOP"]'::jsonb),
  ('963caed1-8447-36ed-5b59-fbe10f6087cb', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Calasparra Cooperative / Hacienda Vieja / Pago de Calasparra', '', 'Calasparra, Murcia', 'M', NULL, 'arrozdecalasparra.com (Consejo Regulador)', 'The Calasparra rice cluster — the canonical Bomba and Balilla X Sollana producer for high-end paella. Cooperative-driven; strong export presence in HoReCa. Reference for premium Spanish paella rice.', 'L3', '["Arroz de Calasparra DOP"]'::jsonb),
  ('1a6a9966-fea8-5de5-2a96-64611dd8acf7', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Arroces Roca / Arroz Bomba (Brands within Spanish rice DOP zones)', '', 'Valencia / Tarragona / Murcia (DOP zones)', 'M', NULL, '', 'For HoReCa volume rice: brands like **Sivaris** (Valencia), **Pons** (Delta), **Hacienda Vieja** (Calasparra). Verify by DOP zone.', 'L3', '["Arroz de Valencia DOP", "Arroz del Delta del Ebro DOP", "Arroz de Calasparra DOP"]'::jsonb)
INSERT INTO producers (producer_id, country_code, country, cluster, producer_name, parent_company, region_town, tier, export_to_eu, website, commercial_notes, source_layer, gis_associated_raw) VALUES
  ('271577f2-6941-aba7-e7e8-b4e7f85515bb', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Herpac (Conservas Herpac) / El Ronqueo / Atún Frescamar', '', 'Barbate, Cádiz, Andalucía', 'M', NULL, 'herpac.com / elronqueo.com', 'Heritage Almadraba-tuna processors. Mojama (dry-cured tuna loin) is iconic Barbate product. Premium gourmet-tier; also bottarga-style, ventresca, atún rojo de almadraba lines.', 'L3', '["Mojama de Barbate IGP / Almadraba traditional tuna"]'::jsonb),
  ('bcbf8467-4c21-4b04-c8e2-fbe04eaeca6f', 'ES', 'Spain', 'Sherry Vinegar / Specialty (Rice, Mojama, etc.)', 'Bodegas Tradición — see Sherry Vinegar above', '', '', 'M', NULL, '', '', 'L3', '[]'::jsonb),
  ('690aa4cd-9d7c-d798-a0cf-e9a41853c713', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Fromageries Marcel Petite', 'Independent family-owned (Petite family)', 'Granges-Narboz (Doubs), Fort Saint-Antoine (Doubs)', 'L', TRUE, 'comte-petite.com', 'Premier French Comté affineur. Two ageing sites: Granges-Narboz (165,000 wheels in brick-and-wood cellars) + Fort Saint-Antoine (100,000 wheels in disused military fort at 1,100m altitude). Sources milk from 35 mountain fruitières. Founded 1932 by Marcel Petite. Reference brand for premium Comté HoReCa export — distributed by Maison Mons, Pomona Passion Froid, Eataly, and major US-EU specialty distributors. Aged 10-30 months at standard, 24-month and Extra-Vieux premium tiers.', 'L3', '["Comté AOP", "Morbier AOP", "Bleu de Gex AOP", "Mont d''Or AOP (Vacherin du Haut-Doubs)", "Raclette du Jura", "Tome de vache"]'::jsonb),
  ('eeba5671-480c-9f7d-16a1-6a2b8b17bac4', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Juraflore (Fromagerie Arnaud)', 'Fromagerie Arnaud', 'Largillay-Marsonnay (Jura)', 'L', TRUE, 'juraflore.com', 'Multiple-time Concours Général Agricole gold medalist for Comté. Premium HoReCa-focused affineur. Strong presence in Paris fine-dining cheese plates.', 'L3', '["Comté AOP", "Morbier AOP", "Mont d''Or AOP"]'::jsonb),
  ('3617829b-164a-3509-608b-6ee34066576e', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Société Fromagère Miroir du Comté', 'Independent', 'Les Fontenelles (Doubs)', 'M', TRUE, '', 'Award-winning artisanal Comté affineur — Concours Général Agricole gold medals. Strong Doubs-mountain terroir positioning.', 'L3', '["Comté AOP"]'::jsonb),
  ('cf73e64d-fa3e-4649-50d7-bda2c5b990b9', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Société Fromagère Thierry Bardey', 'Independent', 'Poligny (Jura)', 'M', TRUE, '', 'Concours Général Agricole gold medalist. Boutique premium positioning.', 'L3', '["Comté AOP"]'::jsonb),
  ('2c81ecb4-fbd3-7759-eac2-d6ea50de5db9', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Fromagerie Vagne / Maison Vagne', '', 'Doubs', 'M', NULL, '', 'Mid-size Franche-Comté multi-AOP producer. Solid HoReCa standby.', 'L3', '["Comté AOP", "Morbier AOP", "Mont d''Or AOP", "Bleu de Gex AOP"]'::jsonb),
  ('a68d702f-4e7d-3bb3-7b1f-cf781118901c', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Monts et Terroirs (Chalet de Vevy)', 'Sodiaal-affiliated', 'Vevy (Jura)', 'L', TRUE, '', 'Industrial-volume but premium-positioned. Reference for HoReCa Morbier supply. Owned by Sodiaal cooperative.', 'L3', '["Morbier AOP (Concours Général Agricole gold medal-winning Morbier)", "Comté AOP", "Beurre AOP (occasional)"]'::jsonb),
  ('e1d3d424-f84a-8aa1-5ee2-9f6715b570a5', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Fromagerie Badoz', '', 'Pontarlier (Doubs)', 'M', NULL, 'badoz.fr', 'Cancoillotte specialist (a melted-cheese spread, regional Jura icon, not AOP). For Iriska, primarily relevant if extending to non-AOP heritage products.', 'L3', '["Cancoillotte (heritage", "not AOP)", "Comté AOP-related"]'::jsonb),
  ('b2dd120d-b418-b816-af55-a9609bfe6596', 'FR', 'France', 'Comté & Jura Mountain Cheeses', 'Fruitière à Comté Les Majors', '', 'Jura', 'S', NULL, '', 'Cooperative of 12 Montbéliarde-cow producers. Direct-to-trade; affined by Marcel Petite. Boutique tier.', 'L3', '["Comté AOP (12-month aged in Marcel Petite''s Fort Saint-Antoine)"]'::jsonb),
  ('344346d3-b572-e836-9bc3-c6f1e0d95bf3', 'FR', 'France', 'Roquefort AOP', 'Société des Caves de Roquefort (Roquefort Société)', 'Lactalis (since 1990)', 'Roquefort-sur-Soulzon (Aveyron)', 'L', TRUE, 'roquefort-societe.com', 'Founded 1851. **~60% volume share of global Roquefort production.** ~1,000 milk-producer farms across the AOP zone. Owned by Lactalis since 1990. The default volume-tier Roquefort for HoReCa worldwide.', 'L3', '["Roquefort AOP"]'::jsonb),
  ('dbb90056-d342-4c82-2115-f569eac23448', 'FR', 'France', 'Roquefort AOP', 'Roquefort Papillon', 'Savencia (since 2019)', 'Roquefort-sur-Soulzon (Aveyron)', 'L', TRUE, 'roquefort-papillon.com', 'Founded 1906 by Paul Alric. ~2,250 tonnes/year. ~130 milk producers (23 organic). Distinctive: **only Roquefort producer to bake its own rye bread in-house** for Penicillium roqueforti cultivation. Range: Rouge (entry-level supermarket), Révélation (premium balanced), Taste Noir (premium intense), Coccinelle (mid-range). Acquired by Savencia 2019 (joining Tartare, Caprice des Dieux, Saint-Albray, Saint-Môret, Elle & Vire).', 'L3', '["Roquefort AOP"]'::jsonb),
  ('ed1d7b53-570b-7c23-44a5-ff51e44c6639', 'FR', 'France', 'Roquefort AOP', 'Roquefort Carles (Fromagerie Carles)', 'Independent (3rd-generation, run by Delphine Carles)', 'Roquefort-sur-Soulzon (Aveyron)', 'S', TRUE, 'roquefort-carles.fr', 'Founded 1930s by François Carles. ~15 milk producers; ~230 tonnes/year. **One of two producers using traditional bread-mold Penicillium method (with Papillon).** Premium artisan tier; favored by US specialty importer Formaggio Kitchen.', 'L3', '["Roquefort AOP"]'::jsonb),
  ('57a8add4-49fe-e551-2ce9-b16409e4bc0f', 'FR', 'France', 'Roquefort AOP', 'Roquefort Vernières Frères', 'Independent (Vernières family, 5th generation; Vernières owned 5 of 18 Roquefort cellars in 1664-1671)', 'Roquefort-sur-Soulzon (Aveyron); cheese dairy at Villefranche-de-Panat (Aveyron)', 'M', TRUE, 'vernieres-freres.com', 'Founded 1890 by Paulin Vernières. ~52 milk producers in Lévézou and Ségala plateau. ~1,200 tonnes/year. Logo: traditional shepherd and "cabanière" surrounding red oval with capital V.', 'L3', '["Roquefort AOP"]'::jsonb),
  ('8b82acdf-54b5-489b-cff2-b53744be5e36', 'FR', 'France', 'Roquefort AOP', 'Roquefort Gabriel Coulet', 'Independent', 'Roquefort-sur-Soulzon (Aveyron)', 'M', TRUE, 'gabriel-coulet.fr', 'Range includes "Le Gabriel Coulet" (entry premium), "La Petite Cave" (premium grown-up style with floral-fruity character). Free cellar visits + 20-min documentary; Coulet family heritage focus.', 'L3', '["Roquefort AOP"]'::jsonb),
  ('46a82a29-fa80-ec8f-0547-f923257e4850', 'FR', 'France', 'Roquefort AOP', 'Roquefort Le Vieux Berger (Yves Combes)', 'Independent (Combes family)', 'Roquefort-sur-Soulzon (Aveyron); cheese dairy at Mayran (Aveyron)', 'S', NULL, '', 'Founded 1923 by Henri Combes (Templar village of Viala-de-Pas-de-Jaux, Larzac). Smallest of the 7 producers. **~180 tonnes/year — only one product: "Le Vieux Berger".** ~8 milk producers (Causse Comtal, Rougier de Marcillac, Ségala plateau). Premium balanced/integrated style — favored by sophisticated cheese plates.', 'L3', '["Roquefort AOP"]'::jsonb),
